import partners from "../../data/partners";

export default function Partners() {
  return (
    <article className="bg-gray-900 mt-16 hidden md:block max-w-7xl mx-auto pb-8">
      <section className="grid grid-cols-2 gap-8 md:grid-cols-6 lg:grid-cols-5 lg:mt-12 sm:mt-32">
        {partners.map((partner) => {
          return (
            <a key={partner.id} href={partner.href} target="_blank" rel="noreferrer" className="opacity-50 hover:opacity-100 duration-500 col-span-1 flex justify-center md:col-span-2 lg:col-span-1">
              <img
                className="h-12"
                src={partner.img}
                alt={partner.name}
              />
            </a>)
        })}
      </section>
    </article>
  );
}

import { Link } from "react-router-dom";

export default function CareerCta() {
  const ResetLocation = () => window.scrollTo(0, 0);
  return (
    <article className="bg-grape-400">
      <section className="max-w-md mx-auto text-center py-16 px-4 sm:max-w-2xl sm:py-24 sm:px-6 lg:px-8 lg:py-32">
        <h2 className="text-3xl font-extrabold sm:text-4xl">
          <span className="block text-white">Looking for a new career?</span>
          <span className="block text-[color:var(--primary-font-color)]">We’re hiring.</span>
        </h2>
        <Link
          onClick={ResetLocation}
          to="/jobs"
          className="mt-8 w-full inline-flex items-center justify-center py-3 px-5 bg-white border border-transparent rounded-md shadow-md text-base font-medium text-grape-600 hover:bg-grape-50 sm:w-auto"
        >
          See open positions
        </Link>
      </section>
    </article>
  )
}

import React from "react";
import { Disclosure } from "@headlessui/react";
import faq from "../../data/faq";

function classNames(...classes) {
  return classes.filter(Boolean).join(" ");
}

export default function FaqList() {
  return (
    <dl className="mt-6 space-y-6 ">
      {faq.map((faq) => (
        <Disclosure as="div" key={faq.question} className="pt-6">
          {({ open }) => (
            <React.Fragment>
              <dt className="text-lg">
                <Disclosure.Button className="text-left w-full flex justify-between items-start text-gray-400">
                  <span className="font-medium text-white">{faq.question}</span>
                  <span className="ml-6 h-7 flex items-center">
                    <svg
                      className={classNames(
                        open ? "-rotate-180" : "rotate-0",
                        "h-6 w-6 transform"
                      )}
                      xmlns="http://www.w3.org/2000/svg"
                      viewBox="0 0 24 24"
                      fill="currentColor">
                      <path
                        fillRule="evenodd"
                        d="M12.53 16.28a.75.75 0 0 1-1.06 0l-7.5-7.5a.75.75 0 0 1 1.06-1.06L12 14.69l6.97-6.97a.75.75 0 1 1 1.06 1.06l-7.5 7.5Z"
                        clipRule="evenodd"
                      />
                    </svg>
                  </span>
                </Disclosure.Button>
              </dt>
              <Disclosure.Panel as="dd" className="mt-2 pr-12">
                <p className="text-base text-gray-500">{faq.answer}</p>
              </Disclosure.Panel>
            </React.Fragment>
          )}
        </Disclosure>
      ))}
    </dl>
  );
}

